class Solution:
    def findAnswer(self, n: int, edges) -> list:
        import heapq
        graph = [[] for _ in range(n)]
        for idx, (a, b, w) in enumerate(edges):
            graph[a].append((b, w, idx))
            graph[b].append((a, w, idx))
        def dijkstra(src):
            dist = [float('inf')] * n
            dist[src] = 0
            heap = [(0, src)]
            while heap:
                d, u = heapq.heappop(heap)
                if d > dist[u]: continue
                for v, w, _ in graph[u]:
                    if dist[u] + w < dist[v]:
                        dist[v] = dist[u] + w
                        heapq.heappush(heap, (dist[v], v))
            return dist
        d0 = dijkstra(0)
        dn = dijkstra(n - 1)
        shortest = d0[n - 1]
        result = [False] * len(edges)
        if shortest == float('inf'):
            return result
        for i, (a, b, w) in enumerate(edges):
            if d0[a] + w + dn[b] == shortest or d0[b] + w + dn[a] == shortest:
                result[i] = True
        return result

