var findAnswer = function(n, edges) {
    const graph = Array.from({length: n}, () => []);
    for (let idx = 0; idx < edges.length; idx++) {
        const [a, b, w] = edges[idx];
        graph[a].push([b, w, idx]);
        graph[b].push([a, w, idx]);
    }
    function dijkstra(src) {
        const dist = new Array(n).fill(Infinity);
        dist[src] = 0;
        const heap = [[0, src]];
        while (heap.length > 0) {
            heap.sort((a, b) => a[0] - b[0]);
            const [d, u] = heap.shift();
            if (d > dist[u]) continue;
            for (const [v, w] of graph[u]) {
                if (dist[u] + w < dist[v]) {
                    dist[v] = dist[u] + w;
                    heap.push([dist[v], v]);
                }
            }
        }
        return dist;
    }
    const d0 = dijkstra(0);
    const dn = dijkstra(n - 1);
    const shortest = d0[n - 1];
    const result = new Array(edges.length).fill(false);
    if (shortest === Infinity) return result;
    for (let i = 0; i < edges.length; i++) {
        const [a, b, w] = edges[i];
        if (d0[a] + w + dn[b] === shortest || d0[b] + w + dn[a] === shortest)
            result[i] = true;
    }
    return result;
};
